import{_ as t,o as r,c as o,a2 as e}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"G02: 董事高階經理人異動審計 — 經營審計專家報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/經營審計/3163_波若威/20260502/G02_董事高階經理人異動審計.md","filePath":"審計報告庫/經營審計/3163_波若威/20260502/G02_董事高階經理人異動審計.md"}'),l={name:"審計報告庫/經營審計/3163_波若威/20260502/G02_董事高階經理人異動審計.md"};function i(n,a,s,h,_,d){return r(),o("div",null,[...a[0]||(a[0]=[e('<p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的經營洞見。</p><h1 id="g02-董事高階經理人異動審計-—-經營審計專家報告" tabindex="-1">G02: 董事高階經理人異動審計 — 經營審計專家報告 <a class="header-anchor" href="#g02-董事高階經理人異動審計-—-經營審計專家報告" aria-label="Permalink to &quot;G02: 董事高階經理人異動審計 — 經營審計專家報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>董事會與高階經理人近三年是否有非正常異動？這對公司目前經營決策與管理穩定度有何影響？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：創辦人吳國精2024年逝世+財會主管2年異動6次，構成雙重治理風險；董總陣營尚穩。</li><li><strong>風險評級</strong>：高</li><li><strong>數據時效</strong>：截至2026年3月</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p><strong>B-（中偏弱）</strong>：董會2023年改選陣容尚穩。三大警訊：(1)財會/稽核主管2023/11起異動6次（含更正公告）；(2)財會主管黃淑君兼代理發言人，內控分工集中；(3)創辦人逝世人脈難複製。黃裕文(總經理)在位9年、研發主管穩定，營運層較無動盪。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="創辦人逝世" tabindex="-1">創辦人逝世 <a class="header-anchor" href="#創辦人逝世" aria-label="Permalink to &quot;創辦人逝世&quot;">​</a></h3><ul><li><strong>核心重點</strong>：吳國精2024年5月膽管癌逝世，享壽74歲。工研院財務主任出身，曾主導入主台灣光罩，生前因炒股案判刑3年2月（逝世後公訴不受理）。</li><li><strong>深度見解</strong>：吳國精2020年已交棒鄭萬來，日常營運衝擊有限。但「泛波若威集團」跨產業整合能力無人能繼，對NVIDIA等大廠的談判能量遠遜於前。</li></ul><h3 id="財會高頻異動" tabindex="-1">財會高頻異動 <a class="header-anchor" href="#財會高頻異動" aria-label="Permalink to &quot;財會高頻異動&quot;">​</a></h3><ul><li><strong>核心重點</strong>：2023/11至2026/3間財會/稽核主管異動累計7次（含更正公告）。黃淑君兼財會主管與代理發言人。</li><li><strong>深度見解</strong>：1-2年內多次更換財會主管屬治理紅燈。更正公告顯示行政內控瑕疵，2024年營業虧損與財會變動期重疊，黃淑君身兼二職不符內控分離原則。</li></ul><h3 id="董總制衡不足" tabindex="-1">董總制衡不足 <a class="header-anchor" href="#董總制衡不足" aria-label="Permalink to &quot;董總制衡不足&quot;">​</a></h3><ul><li><strong>核心重點</strong>：鄭萬來(董)+黃裕文(總)雙核心皆在位5年+，獨董三人（方佩華、孟慶蒞、林建智）。</li><li><strong>深度見解</strong>：獨董偏法律會計背景，無光通訊產業專家，難以實質制衡技術與資本決策。創辦人逝世後缺最終協調者，董總若路線分歧無調解機制。</li></ul><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><ol><li><strong>財會主管頻繁異動內控風險</strong>：不到2年6次異動（含更正公告），顯示公司財會作業流程存在系統性問題。若此情況持續，將大幅增加財報錯誤或延遲公告的風險，對機構法人持股信心構成壓力。財會主管兼代理發言人更使資訊揭露的獨立性受質疑。</li><li><strong>創辦人逝世後的策略談判力斷層</strong>：波若威當前最大的成長動能來自AI資料中心光通訊需求，但與NVIDIA等國際客戶的供應鏈合作談判需要高度專業與人脈。吳國精的工研院+創投人脈網絡無法由鄭萬來或黃裕文複製，可能影響CPO產品量產後的客戶導入進度。</li><li><strong>無明確接班人計劃的潛在壓力</strong>：黃裕文已任總經理9年，目前未見明確的接班人培養規劃。董事長鄭萬來年事亦高。若短期內再有核心經營者健康意外，公司將面臨比2024年更嚴峻的領導真空困境。</li></ol><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><strong>web_search</strong>：波若威近三年董監事經理人異動公告彙整（goodinfo鉅亨網等）</li><li><strong>web_search</strong>：吳國精逝世報導（ETtoday 2024/05, 中央社 2024/05）</li><li><strong>web_search</strong>：黃裕文總經理經歷與任職期間（鉅亨網公司概況, chinatimes 2016）</li><li><strong>web_search</strong>：波若威研發主管異動歷史（ETtoday 2012, 鉅亨網 2019）</li><li><strong>web_search</strong>：2026年波若威經營團隊名單（自由時報, 富邦證券）</li><li><strong>FinMind</strong>：TaiwanStockFinancialStatements (3163, 2023Q1-2025Q4) — 獲利結構驗證</li><li><strong>PDF</strong>：2025_Q4_3163_合併財務報告 — 簽章頁確認董事長鄭萬來、經理人黃裕文、會計主管黃淑君</li></ul>',19)])])}const u=t(l,[["render",i]]);export{c as __pageData,u as default};
